   115→	public forecastStyleTrend({
   116→		styleId,
   117→		historicalData,
   118→		startDate,
   119→		endDate,
   120→		forecastDays,
   121→		bar,
   122→	}: {
   123→		styleId: number;
   124→		historicalData: IProductAnnualSalesBase[];
   125→		startDate: string;
   126→		endDate: string;
   127→		forecastDays: number;
   128→		bar?: ProgressBar;
   129→	}): CompleteForecastResult | null {
   130→		try {
   131→			const endDateDayNumber = this.getDayOfYear(new Date(endDate));
   132→
   133→			const purchasesArr = historicalData.reduce<number[]>((acc, data, index) => {
   134→				if (index === historicalData.length - 1) {
   135→					acc.push(...data.daily_orders.slice(0, endDateDayNumber));
   136→				} else {
   137→					acc.push(...data.daily_orders);
   138→				}
   139→				return acc;
   140→			}, []);
   141→
   142→			const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
   143→				values: purchasesArr,
   144→				alpha: 0.1,
   145→			});
   146→
   147→			const harmonics = this.getHarmonicsByObservationsCount({
   148→				observations: smoothedPurchasesArr.length,
   149→			});
   150→
   151→			const changes = MathematicalFunctions.changePointDetection({
   152→				values: smoothedPurchasesArr,
   153→				significance: 0.02,
   154→				penalty: 0.1,
   155→				minSegmentLength: 40,
   156→			});
   157→
   158→			const yearlyComponent = this.calculateSeasonalComponent({
   159→				values: smoothedPurchasesArr,
   160→				period: 365,
   161→				harmonics,
   162→			});
   163→
   164→			const monthlyComponent = this.calculateSeasonalComponent({
   165→				values: smoothedPurchasesArr,
   166→				period: 30,
   167→				harmonics,
   168→			});
   169→
   170→			const weeklyComponent = this.calculateSeasonalComponent({
   171→				values: smoothedPurchasesArr,
   172→				period: 7,
   173→				harmonics,
   174→			});
   175→
   176→			const quarterlyComponent = this.calculateSeasonalComponent({
   177→				values: smoothedPurchasesArr,
   178→				period: 91,
   179→				harmonics,
   180→			});
   181→
   182→			const trendComponent = this.calculateTrendComponent({
   183→				values: smoothedPurchasesArr,
   184→				changePoints: changes.changePoints,
   185→				startDate: startDate,
   186→				endDate: endDate,
   187→			});
   188→
   189→			const residuals = purchasesArr.map((val, i) => {
   190→				const trend = trendComponent[i] ?? 0;
   191→				const yearly = yearlyComponent[i] ?? 0;
   192→				const monthly = monthlyComponent[i] ?? 0;
   193→				const weekly = weeklyComponent[i] ?? 0;
   194→				const quarterly = quarterlyComponent[i] ?? 0;
   195→				return val - (trend + yearly + monthly + weekly + quarterly);
   196→			});
   197→
   198→			const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
   199→				values: residuals,
   200→				alpha: 0.1,
   201→			});
   202→
   203→			const comprehensiveForecast = this.createComprehensiveForecast({
   204→				yearlyComponent,
   205→				monthlyComponent,
   206→				weeklyComponent,
   207→				quarterlyComponent,
   208→				trendComponent,
   209→				smoothedResidualsArr,
   210→				historicalLength: purchasesArr.length,
   211→				forecastDays,
   212→				endDate,
   213→				purchasesArr,
   214→			});
   215→
   216→			const historicalWindow = 14;
   217→			const historicalOrders = purchasesArr.slice(-historicalWindow);
   218→
   219→			const trendingScoreData = {
   220→				historicalOrders,
   221→				forecastedOrders: comprehensiveForecast.forecastValues,
   222→				trendComponent,
   223→			};
   224→
   225→			const trendingResult =
   226→				TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
   227→
   228→			const trendScore = trendingResult.trendScore;
   229→
   230→			const { trendingReason } = this.calculateTrendingReason({
   231→				comprehensiveForecast,
   232→				historicalOrders,
   233→				trendComponent,
   234→			});
   235→
   236→			const finalTrendingReason = trendingReason;
   237→
   238→			const forecastResult: CompleteForecastResult = {
   239→				style_id: styleId,
   240→				forecast_dates: comprehensiveForecast.forecastDates,
   241→				predicted_orders: comprehensiveForecast.forecastValues,
   242→				trend_score: Math.round(trendScore * 100) / 100,
   243→				trending_reason: finalTrendingReason,
   244→				purchasesArr,
   245→				smoothedPurchasesArr,
   246→				yearlyComponent,
   247→				monthlyComponent,
   248→				weeklyComponent,
   249→				quarterlyComponent,
   250→				trendComponent,
   251→				smoothedResidualsArr,
   252→				comprehensiveForecast,
   253→				changes,
   254→				startDate,
   255→				endDate,
   256→			};
   257→
   258→			if (bar) {
   259→				bar.increment(1);
   260→			}
   261→
   262→			return forecastResult;
   263→		} catch (error) {
   264→			this.logger.error(`Error processing product ${styleId}:`, error);
   265→			if (bar) {
   266→				bar.increment(1);
   267→			}
   268→			return null;
   269→		}
   270→	}
