   324→	private calculateSeasonalComponent({
   325→		values,
   326→		period,
   327→		harmonics,
   328→	}: {
   329→		values: number[];
   330→		period: number;
   331→		harmonics: number;
   332→	}): number[] {
   333→		const n = values.length;
   334→		if (n < period) {
   335→			return new Array(n).fill(0) as number[];
   336→		}
   337→
   338→		try {
   339→			const coefficients = MathematicalFunctions.fourierCoefficients({
   340→				values,
   341→				period,
   342→				harmonics,
   343→				precision: null,
   344→			});
   345→
   346→			const seasonal = MathematicalFunctions.reconstructFourierSeries({
   347→				period,
   348→				harmonics,
   349→				a: coefficients.a,
   350→				b: coefficients.b,
   351→				length: n,
   352→			});
   353→
   354→			return seasonal;
   355→		} catch (error) {
   356→			this.logger.error('Error extending seasonal component', error);
   357→			return values.map((_, index) => {
   358→				const cyclePosition = index % Math.max(1, Math.floor(period));
   359→				const seasonalIndex = Math.min(cyclePosition, values.length - 1);
   360→				return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
   361→			});
   362→		}
   363→	}
   364→
   365→	private calculateTrendComponent({
   366→		values,
   367→		changePoints,
   368→		startDate,
   369→		endDate,
   370→	}: {
   371→		values: number[];
   372→		changePoints: number[];
   373→		startDate: string;
   374→		endDate: string;
   375→	}): number[] {
   376→		const n = values.length;
   377→		if (n === 0) return [];
   378→
   379→		const dates = this.generateDateRange(startDate, endDate, n);
   380→
   381→		if (changePoints.length === 0) {
   382→			return MathematicalFunctions.calculateTrend({ values, dates });
   383→		}
   384→
   385→		const trend = new Array(n).fill(0) as number[];
   386→		const segments = [0, ...changePoints, n];
   387→
   388→		for (let i = 0; i < segments.length - 1; i++) {
   389→			const start = segments[i] as unknown as number;
   390→			const end = segments[i + 1] as unknown as number;
   391→			const segmentValues = values.slice(start, end);
   392→			const segmentDates = dates.slice(start, end);
   393→
   394→			if (segmentValues.length > 1) {
   395→				const segmentTrend = MathematicalFunctions.calculateTrend({
   396→					values: segmentValues,
   397→					dates: segmentDates,
   398→				});
   399→
   400→				for (let j = 0; j < segmentTrend.length; j++) {
   401→					trend[start + j] = segmentTrend[j] as unknown as number;
   402→				}
   403→			} else if (segmentValues.length === 1) {
   404→				trend[start] = segmentValues[0] as unknown as number;
   405→			}
   406→		}
   407→
   408→		return trend;
   409→	}
