   543→	private extendSeasonalComponent(
   544→		component: number[],
   545→		period: number,
   546→		harmonics: number,
   547→		historicalLength: number,
   548→		forecastDates: string[],
   549→		endDate: string,
   550→	): number[] {
   551→		if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
   552→
   553→		try {
   554→			const coefficients = MathematicalFunctions.fourierCoefficients({
   555→				values: component,
   556→				period,
   557→				harmonics,
   558→				precision: null,
   559→			});
   560→
   561→			const forecastValues: number[] = [];
   562→			const endDateObj = new Date(endDate);
   563→
   564→			for (const forecastDate of forecastDates) {
   565→				const forecastDateObj = new Date(forecastDate);
   566→
   567→				const daysDiff = Math.floor(
   568→					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   569→				);
   570→
   571→				const cyclePosition = (historicalLength + daysDiff) % period;
   572→				const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
   573→					period,
   574→					harmonics,
   575→					a: coefficients.a,
   576→					b: coefficients.b,
   577→					length: Math.ceil(cyclePosition) + 1,
   578→					a0: 0,
   579→				});
   580→
   581→				const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
   582→				forecastValues.push(seasonalValue);
   583→			}
   584→
   585→			return forecastValues;
   586→		} catch (error) {
   587→			this.logger.error('Error extending seasonal component', error);
   588→			return forecastDates.map((forecastDate) => {
   589→				const endDateObj = new Date(endDate);
   590→				const forecastDateObj = new Date(forecastDate);
   591→				const daysDiff = Math.floor(
   592→					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   593→				);
   594→				const flooredPeriod = Math.max(1, Math.floor(period));
   595→				const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
   596→				const historicalIndex = Math.min(cyclePosition, component.length - 1);
   597→				return component[historicalIndex] ?? 0;
   598→			});
   599→		}
   600→	}
