   602→	private extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
   603→		if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
   604→
   605→		const recentTrendPoints = Math.min(30, trendComponent.length);
   606→		const recentTrend = trendComponent.slice(-recentTrendPoints);
   607→
   608→		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
   609→		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
   610→
   611→		const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
   612→		const trendSlope = regression.slope;
   613→
   614→		return Array(forecastDays)
   615→			.fill(0)
   616→			.map((_, i) => {
   617→				const decay = Math.exp(-0.02 * i);
   618→				return lastValue + trendSlope * (i + 1) * decay;
   619→			});
   620→	}
   621→
   622→	private extendResidualsComponent({
   623→		smoothedResidualsArr,
   624→		forecastDays,
   625→		endDate,
   626→	}: {
   627→		smoothedResidualsArr: number[];
   628→		forecastDays: number;
   629→		endDate: string;
   630→	}): number[] {
   631→		if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
   632→			return Array(forecastDays).fill(0) as number[];
   633→		}
   634→
   635→		const twoWeeksLength = 7;
   636→		const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
   637→		const recentResiduals = smoothedResidualsArr.slice(-trendLength);
   638→
   639→		const endDateObj = new Date(endDate);
   640→		const dates = recentResiduals.map((_, i) => {
   641→			const date = new Date(endDateObj);
   642→			date.setDate(endDateObj.getDate() - (trendLength - i - 1));
   643→			const dateArr = date.toISOString().split('T') as [string, string];
   644→			return dateArr[0];
   645→		});
   646→
   647→		const trendValues = MathematicalFunctions.calculateTrend({
   648→			values: recentResiduals,
   649→			dates,
   650→		});
   651→
   652→		if (trendValues.length === 0) {
   653→			return Array(forecastDays).fill(0) as number[];
   654→		}
   655→
   656→		const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
   657→		const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
   658→
   659→		const lastIndex = recentResiduals.length - 1;
   660→		return Array(forecastDays)
   661→			.fill(0)
   662→			.map((_, i) => {
   663→				return regression.slope * (lastIndex + i + 1) + regression.intercept;
   664→			});
   665→	}
