   690→	private calculateTrendingReason({
   691→		comprehensiveForecast,
   692→		historicalOrders,
   693→		trendComponent,
   694→	}: {
   695→		comprehensiveForecast: {
   696→			forecastValues: number[];
   697→			forecastDates: string[];
   698→			components: {
   699→				yearly: number[];
   700→				monthly: number[];
   701→				weekly: number[];
   702→				quarterly: number[];
   703→				trend: number[];
   704→				residuals: number[];
   705→			};
   706→		};
   707→		historicalOrders: number[];
   708→		trendComponent: number[];
   709→	}): { trendingReason: string; growthRate: number } {
   710→		if (
   711→			historicalOrders.length === 0 ||
   712→			comprehensiveForecast.forecastValues.length === 0
   713→		) {
   714→			return { trendingReason: 'Stable pattern', growthRate: 0 };
   715→		}
   716→
   717→		const historicalAvg =
   718→			historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
   719→		const forecastAvg =
   720→			comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
   721→			comprehensiveForecast.forecastValues.length;
   722→
   723→		const growthRate =
   724→			historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;
   725→
   726→		const trendSlope = this.calculateTrendSlope(trendComponent);
   727→
   728→		if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
   729→			return { trendingReason: 'Strong growth forecast', growthRate };
   730→		} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
   731→			return { trendingReason: 'Moderate growth forecast', growthRate };
   732→		} else if (growthRate > 0 || trendSlope >= 0.05) {
   733→			return { trendingReason: 'Positive trend detected', growthRate };
   734→		} else {
   735→			return { trendingReason: 'Stable pattern', growthRate };
   736→		}
   737→	}
   738→
   739→	private calculateTrendSlope(trendComponent: number[]): number {
   740→		if (trendComponent.length < 2) return 0;
   741→
   742→		const recentPoints = Math.min(14, trendComponent.length);
   743→		const recentTrend = trendComponent.slice(-recentPoints);
   744→
   745→		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
   746→		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
   747→
   748→		return regression.slope;
   749→	}
   750→}
