    18→import { fastifyHttpLogger } from '@middlewares/logger.middleware';
    19→
    20→import {
    21→	NODE_ENV,
    22→	PORT,
    23→	SERVER_NAME,
    24→	GLOBAL_PREFIX,
    25→	IS_COMPACT_LOGS,
    26→	IS_JSON_LIKE_LOGS,
    27→} from '@constants/env-variables.constant';
    28→
    29→import { Environment } from '@interfaces/env-variables.interface';
    30→
    31→import { NewrelicInterceptor } from '@interceptors/newrelic.interceptor';
    32→
    33→async function bootstrap() {
    34→	const globalPrefix = getEnv<string>({ key: GLOBAL_PREFIX });
    35→	const port = getEnv<number>({ key: PORT, converter: Number });
    36→	const nodeEnv = getEnv<Environment>({ key: NODE_ENV });
    37→	const serverName = getEnv<string>({ key: SERVER_NAME });
    38→	const isCompactLogs = getEnv<boolean>({ key: IS_COMPACT_LOGS, converter: Boolean });
    39→	const isJsonLikeLogs = getEnv<boolean>({ key: IS_JSON_LIKE_LOGS, converter: Boolean });
    40→	const isDev = nodeEnv === Environment.DEVELOPMENT;
    41→	const isProdOrStaging =
    42→		nodeEnv === Environment.PRODUCTION || nodeEnv === Environment.STAGING;
    43→
    44→	const logger = new RecoConsoleLogger({
    45→		logLevels: isDev
    46→			? ['log', 'error', 'warn', 'fatal', 'debug', 'verbose']
    47→			: ['log', 'error', 'warn', 'fatal'],
    48→		colors: isDev,
    49→		prefix: serverName,
    50→		compact: isCompactLogs,
    51→		json: isJsonLikeLogs,
    52→	});
    53→
    54→	const fastifyAdapter = new FastifyAdapter({
    55→		trustProxy: true,
    56→	});
    57→	fastifyAdapter.getInstance().register(fastifyHttpLogger);
    58→
    59→	const app = await NestFactory.create<NestFastifyApplication>(
    60→		AppModule,
    61→		fastifyAdapter,
    62→		{ bodyParser: false, rawBody: true, logger },
    63→	);
    64→
    65→	if (nodeEnv !== Environment.PRODUCTION) {
    66→		setupSwagger(app, fastifyAdapter, globalPrefix);
    67→	}
    68→
    69→	app.enableCors({ origin: true, credentials: true });
    70→
    71→	app.use((req: FastifyRequest['raw'], res: FastifyReply['raw'], next: () => void) => {
    72→		const middleware = new CorrelationIdMiddleware();
    73→		middleware.use(req, res, next);
    74→	});
    75→
    76→	if (isProdOrStaging) {
    77→		app.useGlobalInterceptors(
    78→			new NewrelicInterceptor(await app.resolve<NewrelicService>(NewrelicService)),
    79→		);
    80→		app.useGlobalFilters(new RollbarExceptionFilter());
    81→	}
    82→
    83→	app.useGlobalFilters(new BadRequestExceptionFilter());
    84→
    85→	app.useGlobalPipes(
    86→		new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
    87→	);
    88→
    89→	app.setGlobalPrefix(globalPrefix, {
    90→		exclude: ['is_it_up', 'is_it_working', 'is_it_ready', 'robots.txt'],
    91→	});
    92→
    93→	app.enableShutdownHooks();
    94→
    95→	logger.log(`[Main file] Application is running on ${String(port)} port`);
    96→	await app.listen(port);
    97→
    98→	const LogShutDown = (signal: string): void => {
    99→		logger.log(`Received ${signal} server is shutting down`);
   100→	};
   101→	process.on('SIGINT', LogShutDown);
   102→	process.on('SIGTERM', LogShutDown);
   103→}
   104→
